INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('customs-f19eb2bd-moex-00437', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-01c5eaab', 'sub-customs-f19eb2bd-05', NULL, 'single_choice', '「在我們的文化裡，哪裡有『母女專屬時間』這個概念？這個社會向來談 的都是我們要給孩子相處的『品質時間』，陪伴孩子長大，什麼人談過我 們要給父母『品質時間』，陪伴他們老去？我在紐約咖啡館裡坐著的時候， 美君你正在高雄路竹的鄉下養豬，女兒出國深造，兩個弟弟大學還沒畢業， 你們仍然在勞動，為了下一代的教育。」下列選項，最符合上文主旨的是：', '["感念母親犧牲，才能讓自己出國深造", "母親養豬栽培子女，自己卻不及報恩", "不該讓母親長住鄉下，搬到都市才好", "母親一生辛勞，應陪伴她過晚年生活"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:27+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00438', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-01c5eaab', 'sub-customs-f19eb2bd-05', NULL, 'single_choice', '「如今這個世界，已經被我們自己弄得烏煙瘴氣、混亂不堪了。權力的爭 奪、武器的競賽、道德的墮落，累世不斷、緜延不已的仇恨與謀殺……太 多的負面狀況出現在我們周遭，做為一個有理想、有感知的人，活在今天， 是傷心的，但是，出以己身既蒙天地之愛而生為人，我們便應以愛還報世 界的使命感，以及對整體人類所懷抱的悲憫與大愛，仍願意抱持『知其不 可而為之』的態度去努力，去改善一點什麼。當然，我們並不是一無弱點 的人，但是，在真誠的面對每天的生活與工作中，我們得以愛提升自己， 同時也提升這個世界；在廣宇悠宙之間，我們要永遠懷著不死的理想，堅 定地相信——有一天，在那遙遠之處，所有的人類，終將以愛相遇。」下 列選項，何者最切合上文意旨？', '["世界混亂，但求以愛彌補缺憾", "人間有愛，我們都應該珍惜彼此的相遇", "天地不仁，理當彼此競爭才能進步提升", "世界既然不會改變，更要好好生活與工作"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:27+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00439', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-01c5eaab', 'sub-customs-f19eb2bd-05', NULL, 'single_choice', '承上題，關於上文，下列敘述何者較不適當？', '["提升自己也等同於改善世界", "要努力的原因是因為想把愛還諸天地", "傷心的原因是因為感受到自己的生活艱苦", "人類以愛相遇代表著人與人之間充滿愛與關懷"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:27+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00440', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-01c5eaab', 'sub-customs-f19eb2bd-05', NULL, 'single_choice', '「在漫步時我的腦中並非一片空白，它有時喚起童年抬便當聞到的氣味： 那是班上五十個孩子便當混在一起的氣味，……如果仔細回想，就知道一 張在街頭獲得的照片不會只是按快門的一瞬，它是一段插敘不斷的敘事， 一張照片喚起的可能是人類獨有的，涉及自我覺知與複雜經驗的記憶形 式。」假設以上文字是美術館某項展覽的文案，下列何者最適合？', '["版印年畫特展", "畫說保存維護特展", "台糖百年蔗糖影像展", "人體素描與石膏雕塑展"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:27+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00441', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-01c5eaab', 'sub-customs-f19eb2bd-05', NULL, 'single_choice', '「成功，其實可以很簡單！不是看職位高低、財富多少；而是心中有夢想、 手中有做法。歐洲理財大師博多・雪佛對成功提出一個與眾不同的定義， 他說：『成功，是按照自己所建構的生活藍圖，去操控自己的生活。』不 論現在的成就如何，只要能夠認清自己的目標，誠懇地接受自己目前的處 境，對其中有些需要改進的地方全力以赴，願意繼續認真地向前走，這個 過程就是成功。」根據上文，下列選項何者錯誤？', '["職位的高低與財富多少，不能定義何謂成功", "能主導公司發展的方向並掌握資源，才能獲得成功", "成功就是依照自己所擘劃的藍圖，讓自己能操控生活", "成功不看目前的成就，而是能認清目標與處境並持續的努力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:27+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00442', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-01c5eaab', 'sub-customs-f19eb2bd-05', NULL, 'single_choice', '「人的覺悟常是心上剎那間事。能忽然發現到井口的天光，發現自己是井 底的人兒，已是偶然了，如何爬上去就更艱難。」下列選項，何者最貼合 上文的旨意？', '["井底之蛙視野有限，要超越侷限處處碰壁", "天光猶如理想的召喚，但要達成心願很艱難", "人若不知自我反省，要成就一番事業便困難重重", "人就算察覺自己的不足，真要有所成長談何容易"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:27+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00443', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-01c5eaab', 'sub-customs-f19eb2bd-05', NULL, 'single_choice', '「真奈排在等待快車的人龍後面，從口袋裡掏出口罩遮住臉。定睛一看， 周圍的人十有八九都戴著口罩，不分男女老少。大概是為了預防流感和花 粉症吧，但是冷靜想想，還真是匪夷所思的光景。一大群戴著口罩的人全 都低著頭，把玩手裡的手機。剛來東京念專門學校時，真奈真的很討厭擠 滿人的電車，難以相信每天上學都必須與陌生人緊貼身體。所以都會的人 才會在不知不覺間這麼依賴口罩，不只是為了預防病毒或花粉，也是為了 保護自己。痛恨與陌生人緊貼身體，卻又目不轉睛地關注著就連在哪兒都 不知道的陌生人的『自言自語』。這輛電車上恐怕有一半以上的乘客都在 做跟自己相同的事。仔細想想，果然是不太正常的光景。」下列選項，何 者最可能是上述短文中所提到的「自言自語」？', '["低頭看手機上的文章，並低聲唸出", "好奇心旺盛，很想知道別人在自言自語什麼", "依賴社群軟體，無時無刻盯著網路上他人的訊息", "因怕被傳染而戴上口罩，無法和人交談，只能自言自語"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:27+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00444', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-01c5eaab', 'sub-customs-f19eb2bd-05', NULL, 'single_choice', '「據說秦始皇有一次想把他的苑囿擴大，大得東到函谷關，西到今天的鳳 翔和寶鷄。宮中的弄臣優旃說：『妙極了！多放些動物在裏面吧。要是敵 人從東邊打過來，只要教糜鹿用角去抵抗，就夠了。』秦始皇聽了，就把 這計畫擱了下來。這麼看來，幽默實在是荒謬的解藥。委婉的幽默，往往 順著荒謬的邏輯誇張下去，使人領悟荒謬的後果。幽默並不等於尖刻，因 為幽默針對的不是荒謬的人，而是荒謬本身。真正幽默的心靈，絕不抱定 一個角度去看人或看自己，他不但會幽默人，也會幽默自己，不但嘲笑人， 也會釋然自嘲，泰然自貶。」根據上文，秦始皇擱置計畫最可能的原因是：', '["苑囿過大容易引起敵人覬覦田獵之利", "瞭解光靠訓練糜鹿無法遏阻強敵入侵", "苑中動物會妨礙軍事訓練，不利抗敵", "擴建苑囿恐勞民傷財，不能克敵致勝"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:27+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00445', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-01c5eaab', 'sub-customs-f19eb2bd-05', NULL, 'single_choice', '承上題，下列對於「幽默」的詮釋，最適合的是：', '["真正具幽默感的人往往善於自我嘲弄與自我貶抑", "幽默與荒謬並存，幽默的心靈亦有其荒謬的一面", "幽默可降低言語的殺傷力，使荒謬之感獲得淡化", "將荒謬的邏輯加以誇張，尖刻與幽默皆獲得強化"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:27+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00446', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-01c5eaab', 'sub-customs-f19eb2bd-05', NULL, 'single_choice', '「這樣不推銷的推銷術，在這裡最合適。有些店舖，主顧上門，不但不著 急兜攬生意，而且於客氣之中寓有生疏之意。例如書店，進得店門，四壁 圖書雖然塞得滿滿的，但盡是些普通書籍，你若問他有什麼好書，他說沒 有什麼，你說隨便看看，他說請看請看。結果是你什麼好書也看不見，但 是你若去過幾次，做成幾回生意，情形就不同了，他會請你到裡櫃坐，再 過些時請到後櫃坐，升堂入室之後，箱子裡的好書善本陸陸續續的都拿出 來了。宋版的，元槧的，琳琅滿目，還小聲的囑咐你，不要對外人說，生 意之外，還套著交情。」下列選項，何者最能形容文中的推銷術？', '["深藏若虛", "虛懷若谷", "明褒暗貶", "循循善誘"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:27+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL)
